// Generated fixture modules.
// Each format has its own file, generated by `build.rs` from `spec/fixtures/{format}.yaml`.
// Do not edit by hand.

pub mod pml;
pub mod sml;
pub mod wml;

/// Return all generated fixtures across all formats.
pub fn all_fixtures() -> Vec<crate::Fixture> {
    let mut all = Vec::new();
    all.extend(wml::all_fixtures());
    all.extend(sml::all_fixtures());
    all.extend(pml::all_fixtures());
    all
}
